import{_ as a,c as t,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse(`{"title":"FAQ : Dépannage OAuth & Modèles | Antigravity Auth","description":"Découvrez les problèmes courants et leurs solutions pour le plugin Antigravity Auth. Guide pratique couvrant le dépannage OAuth, la gestion des erreurs de modèles introuvables et la configuration de compatibilité des plugins.","frontmatter":{"title":"FAQ : Dépannage OAuth & Modèles | Antigravity Auth","sidebarTitle":"Échec d'authentification","subtitle":"FAQ : Dépannage OAuth & Modèles","description":"Découvrez les problèmes courants et leurs solutions pour le plugin Antigravity Auth. Guide pratique couvrant le dépannage OAuth, la gestion des erreurs de modèles introuvables et la configuration de compatibilité des plugins.","order":4},"headers":[],"relativePath":"fr/NoeFabris/opencode-antigravity-auth/faq/index.md","filePath":"fr/NoeFabris/opencode-antigravity-auth/faq/index.md"}`),n={name:"fr/NoeFabris/opencode-antigravity-auth/faq/index.md"};function o(s,e,l,u,d,c){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="questions-frequentes" tabindex="-1">Questions Fréquentes <a class="header-anchor" href="#questions-frequentes" aria-label="Permalink to &quot;Questions Fréquentes&quot;">​</a></h1><p>Cette section recense les problèmes les plus courants rencontrés lors de l&#39;utilisation du plugin Antigravity Auth, ainsi que leurs solutions. Que vous rencontriez des échecs d&#39;authentification OAuth, des erreurs de requêtes de modèles ou des problèmes de compatibilité, vous trouverez ici des guides de dépannage appropriés.</p><h2 id="prerequis" tabindex="-1">Prérequis <a class="header-anchor" href="#prerequis" aria-label="Permalink to &quot;Prérequis&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Vérifiez avant de commencer</p><ul><li>✅ <a href="./../start/quick-install/">Installation Rapide</a> terminée et compte ajouté avec succès</li><li>✅ <a href="./../start/first-auth-login/">Première Authentification</a> complétée et flux OAuth compris</li></ul></div><h2 id="parcours-d-apprentissage" tabindex="-1">Parcours d&#39;Apprentissage <a class="header-anchor" href="#parcours-d-apprentissage" aria-label="Permalink to &quot;Parcours d&#39;Apprentissage&quot;">​</a></h2><p>Selon le type de problème que vous rencontrez, sélectionnez le guide de dépannage approprié :</p><h3 id="_1-depannage-echec-oauth" tabindex="-1">1. <a href="./common-auth-issues/">Dépannage Échec OAuth</a> <a class="header-anchor" href="#_1-depannage-echec-oauth" aria-label="Permalink to &quot;1. [Dépannage Échec OAuth](./common-auth-issues/)&quot;">​</a></h3><p>Résolvez les problèmes courants liés à l&#39;authentification OAuth, au rafraîchissement des jetons et aux comptes.</p><ul><li>L&#39;autorisation du navigateur réussit mais le terminal indique « échec d&#39;autorisation »</li><li>Erreur soudaine « Permission Denied » ou « invalid_grant »</li><li>Échec de rappel OAuth sur Safari</li><li>Impossible de terminer l&#39;authentification en environnement WSL2/Docker</li></ul><h3 id="_2-migration-de-compte" tabindex="-1">2. <a href="./migration-guide/">Migration de Compte</a> <a class="header-anchor" href="#_2-migration-de-compte" aria-label="Permalink to &quot;2. [Migration de Compte](./migration-guide/)&quot;">​</a></h3><p>Migrez des comptes entre machines et gérez les mises à jour de version.</p><ul><li>Migration de compte d&#39;un ancien ordinateur vers un nouveau</li><li>Comprendre les changements de format de stockage (v1/v2/v3)</li><li>Résolution des erreurs invalid_grant après migration</li></ul><h3 id="_3-depannage-modele-introuvable" tabindex="-1">3. <a href="./model-not-found/">Dépannage Modèle Introuvable</a> <a class="header-anchor" href="#_3-depannage-modele-introuvable" aria-label="Permalink to &quot;3. [Dépannage Modèle Introuvable](./model-not-found/)&quot;">​</a></h3><p>Résolvez les problèmes liés aux modèles, erreurs 400, etc.</p><ul><li>Dépannage de l&#39;erreur « Model not found »</li><li>Erreur 400 « Invalid JSON payload received. Unknown name &quot;parameters&quot; »</li><li>Erreur d&#39;appel du serveur MCP</li></ul><h3 id="_4-compatibilite-des-plugins" tabindex="-1">4. <a href="./plugin-compatibility/">Compatibilité des Plugins</a> <a class="header-anchor" href="#_4-compatibilite-des-plugins" aria-label="Permalink to &quot;4. [Compatibilité des Plugins](./plugin-compatibility/)&quot;">​</a></h3><p>Résolvez les problèmes de compatibilité avec les plugins oh-my-opencode, DCP, etc.</p><ul><li>Configuration correcte de l&#39;ordre de chargement des plugins</li><li>Désactivation des méthodes d&#39;authentification conflictuelles dans oh-my-opencode</li><li>Activation du décalage PID pour les scénarios d&#39;agents parallèles</li></ul><h3 id="_5-avertissement-tos" tabindex="-1">5. <a href="./tos-warning/">Avertissement ToS</a> <a class="header-anchor" href="#_5-avertissement-tos" aria-label="Permalink to &quot;5. [Avertissement ToS](./tos-warning/)&quot;">​</a></h3><p>Comprenez les risques d&#39;utilisation et évitez les bannissements de compte.</p><ul><li>Comprendre les restrictions des Conditions d&#39;Utilisation de Google</li><li>Identifier les scénarios à haut risque (nouveaux comptes, requêtes intenses)</li><li>Maîtriser les meilleures pratiques pour éviter les bannissements</li></ul><h2 id="localisation-rapide-des-problemes" tabindex="-1">Localisation Rapide des Problèmes <a class="header-anchor" href="#localisation-rapide-des-problemes" aria-label="Permalink to &quot;Localisation Rapide des Problèmes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptôme</th><th>Lecture Recommandée</th></tr></thead><tbody><tr><td>Échec d&#39;authentification, délai d&#39;autorisation dépassé</td><td><a href="./common-auth-issues/">Dépannage Échec OAuth</a></td></tr><tr><td>invalid_grant, Permission Denied</td><td><a href="./common-auth-issues/">Dépannage Échec OAuth</a></td></tr><tr><td>Model not found, erreur 400</td><td><a href="./model-not-found/">Dépannage Modèle Introuvable</a></td></tr><tr><td>Conflit avec d&#39;autres plugins</td><td><a href="./plugin-compatibility/">Compatibilité des Plugins</a></td></tr><tr><td>Changement d&#39;ordinateur, mise à jour de version</td><td><a href="./migration-guide/">Migration de Compte</a></td></tr><tr><td>Préoccupations sur la sécurité du compte</td><td><a href="./tos-warning/">Avertissement ToS</a></td></tr></tbody></table><h2 id="prochaines-etapes" tabindex="-1">Prochaines Étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines Étapes&quot;">​</a></h2><p>Une fois le problème résolu, vous pouvez :</p><ul><li>📖 Lire <a href="./../advanced/">Fonctionnalités Avancées</a> pour maîtriser les fonctionnalités avancées comme le multi-compte et la récupération de session</li><li>📚 Consulter l&#39;<a href="./../appendix/">Annexe</a> pour comprendre la conception de l&#39;architecture et la référence complète de configuration</li><li>🔄 Suivre le <a href="./../changelog/">Journal des Modifications</a> pour obtenir les dernières fonctionnalités et changements</li></ul>',26)])])}const m=a(n,[["render",o]]);export{h as __pageData,m as default};
